import{_ as i,o as a,c as s,ai as t}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Types and Widths","description":"","frontmatter":{"title":"Types and Widths","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/type-width-system.md","filePath":"reference-manual/type-width-system.md"}'),n={name:"reference-manual/type-width-system.md"};function l(o,e,d,r,c,p){return a(),s("div",null,[...e[0]||(e[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/type-width-system.md for this page in Markdown format</div><h1 id="types-and-widths" tabindex="-1">Types and Widths <a class="header-anchor" href="#types-and-widths" aria-label="Permalink to “Types and Widths”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>JZ-HDL enforces precise bit widths everywhere. Sizes are explicit (no unsized literals) and most binary operators require equal operand widths. When widths differ, explicit extension modifiers (zero/sign) or intrinsic operators must be used. Unknown (<code>x</code>) and tri‑state (<code>z</code>) bits propagate with strict rules: they may never reach observable sinks unless provably masked.</p><hr><h2 id="literals" tabindex="-1">Literals <a class="header-anchor" href="#literals" aria-label="Permalink to “Literals”">​</a></h2><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to “Syntax”">​</a></h3><p>A sized literal has form:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;width&gt;&#39;&lt;base&gt;&lt;value&gt;</span></span></code></pre></div><ul><li><strong>width</strong>: positive integer or <code>CONST</code> name (compile‑time constant)</li><li><strong>base</strong>: one of <code>b</code>, <code>d</code>, <code>h</code></li><li><strong>value</strong>: digits (underscores <code>_</code> allowed for readability, not leading/trailing)</li></ul><p>Examples:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>8&#39;b1010_0001</span></span>
<span class="line"><span>16&#39;hFF00</span></span>
<span class="line"><span>12&#39;d4095</span></span></code></pre></div><h3 id="bases-and-allowed-digits" tabindex="-1">Bases and allowed digits <a class="header-anchor" href="#bases-and-allowed-digits" aria-label="Permalink to “Bases and allowed digits”">​</a></h3><ul><li><code>b</code> (binary): digits <code>0</code>, <code>1</code>, <code>x</code>, <code>z</code>, and <code>_</code> (underscores ignored)</li><li><code>d</code> (decimal): digits <code>0–9</code>, <code>_</code> only (no <code>x</code>/<code>z</code>)</li><li><code>h</code> (hex): digits <code>0–9</code>, <code>A–F</code>/<code>a–f</code>, <code>_</code> only (no <code>x</code>/<code>z</code>)</li></ul><p>Unsized literals (e.g., <code>&#39;hFF</code>) are illegal and cause compile errors.</p><h3 id="intrinsic-bit‐width-and-extension" tabindex="-1">Intrinsic bit‑width and extension <a class="header-anchor" href="#intrinsic-bit‐width-and-extension" aria-label="Permalink to “Intrinsic bit‑width and extension”">​</a></h3><ul><li>Intrinsic width: <ul><li>Binary: number of digits (excluding <code>_</code>) in the value field</li><li>Decimal/Hex: minimal bits needed to represent the integer (value 0 → width 1)</li></ul></li><li>If intrinsic width is less than declared width, the literal is extended based on the MSB digit of the intrinsic value: <ul><li>MSB = <code>0</code> or <code>1</code>: zero‑extend (pad with <code>0</code>)</li><li>MSB = <code>x</code>: extend with <code>x</code> bits</li><li>MSB = <code>z</code>: extend with <code>z</code> bits (binary only)</li></ul></li><li>If intrinsic width exceeds declared width → compile error (overflow).</li></ul><p>Examples:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>4&#39;bx         // intrinsic 1 → extends to 4&#39;bxxxx</span></span>
<span class="line"><span>8&#39;hF        // intrinsic 4 → zero-extended to 8&#39;h0F</span></span>
<span class="line"><span>25&#39;h1FFFFFF // intrinsic 25 → fits; OK</span></span>
<span class="line"><span>25&#39;h3FFFFFF // intrinsic 26 -&gt; ERROR: overflow</span></span></code></pre></div><h3 id="x-and-z-semantics-in-literals" tabindex="-1"><code>x</code> and <code>z</code> semantics in literals <a class="header-anchor" href="#x-and-z-semantics-in-literals" aria-label="Permalink to “x and z semantics in literals”">​</a></h3><ul><li><code>x</code>: intentional don&#39;t‑care; allowed only in binary literals. <ul><li>Any expression containing <code>x</code> bits is considered x‑dependent.</li><li>X‑dependent values may only be used if every <code>x</code> bit is provably masked before reaching any observable sink.</li></ul></li><li><code>z</code>: high‑impedance (tri‑state). Allowed only in binary literals. <ul><li>Tri‑state bits are permitted for INOUT/tri‑state uses, but nets read must have at least one active (0/1) driver for each bit.</li></ul></li></ul><p>Forbidden uses:</p><ul><li>Register reset literals and MEM initializers must not contain <code>x</code> or <code>z</code>.</li><li><code>x</code>/<code>z</code> digits used in <code>h</code> or <code>d</code> literals → compile error.</li></ul><hr><h2 id="bit‐width-constraints" tabindex="-1">Bit‑Width Constraints <a class="header-anchor" href="#bit‐width-constraints" aria-label="Permalink to “Bit‑Width Constraints”">​</a></h2><h3 id="strict-matching-rule" tabindex="-1">Strict matching rule <a class="header-anchor" href="#strict-matching-rule" aria-label="Permalink to “Strict matching rule”">​</a></h3><p>Most binary operators and many constructs require identical operand widths. Violations produce compile errors.</p><p>Operators requiring equal widths include:</p><ul><li>Arithmetic: <code>+</code>, <code>-</code> (binary)</li><li>Bitwise: <code>&amp;</code>, <code>|</code>, <code>^</code></li><li>Comparisons: <code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code></li><li>Equality/relational operators</li><li>Many intrinsics where specified (exceptions below)</li></ul><h3 id="extension-modifiers" tabindex="-1">Extension modifiers <a class="header-anchor" href="#extension-modifiers" aria-label="Permalink to “Extension modifiers”">​</a></h3><p>When you intentionally connect signals of different widths, use explicit modifiers so the compiler and synthesizer know how to extend bits:</p><p>Operator suffixes (applied to <code>=</code>, <code>=&gt;</code>, <code>&lt;=</code>):</p><ul><li><code>z</code> — zero‑extend the narrower side</li><li><code>s</code> — sign‑extend the narrower side</li></ul><p>Valid forms:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>a =z b;     // alias: b zero-extended to a&#39;s width, then aliased</span></span>
<span class="line"><span>a &lt;=s b;    // receive with sign-extend</span></span>
<span class="line"><span>driver =&gt;z sink;</span></span></code></pre></div><p>Rules:</p><ul><li>If widths are equal, bare operator is fine; <code>z</code>/<code>s</code> are allowed but redundant.</li><li>If widths differ and no modifier is present → compile error.</li><li>Truncation is never implicit. If RHS wider than LHS → compile error.</li><li>Alias operators (<code>=</code> family) may not have a bare literal RHS (use directional assign to drive constants).</li></ul><h3 id="concatenation-decomposition" tabindex="-1">Concatenation &amp; decomposition <a class="header-anchor" href="#concatenation-decomposition" aria-label="Permalink to “Concatenation &amp; decomposition”">​</a></h3><ul><li>Concatenation <code>{a, b, c}</code> produces width = sum(width(a), width(b), ...)</li><li>When assigning to a concatenation, the RHS expression width must equal the concatenation width, unless <code>=z</code>/<code>=s</code> modifier is used to extend the RHS.</li><li>In synchronous assignments the decomposition <code>{r_hi, r_lo} &lt;= expr;</code> distributes MSB→first element.</li></ul><hr><h2 id="operator-width-rules" tabindex="-1">Operator Width Rules <a class="header-anchor" href="#operator-width-rules" aria-label="Permalink to “Operator Width Rules”">​</a></h2><p>Summary (result width relative to operand widths):</p><ul><li>Unary arithmetic (<code>-</code>, <code>+</code>): only on width‑1 operands; result width = 1</li><li>Binary add/sub (<code>+</code>, <code>-</code>): operands must match; result width = operand width (overflow truncated)</li><li>Multiply (<code>*</code>): operands must match; result width = 2 * width (full product)</li><li>Divide/Modulus (<code>/</code>, <code>%</code>): operands must match; result width = dividend width; divisor = 0 at compile time → error</li><li>Bitwise (<code>&amp;</code>, <code>|</code>, <code>^</code>, <code>~</code>): operands must match; result width = operand width</li><li>Logical (<code>&amp;&amp;</code>, <code>||</code>, <code>!</code>): operands width‑1; result width = 1</li><li>Comparison (<code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code>): operands must match; result width = 1</li><li>Shift (<code>&lt;&lt;</code>, <code>&gt;&gt;</code>, <code>&gt;&gt;&gt;</code>): LHS width retained</li><li>Ternary <code>cond ? a : b</code>: cond width‑1; a and b widths must match; result = operand width</li><li>Concatenation <code>{}</code>: result width = sum of inputs</li></ul><p>Important notes:</p><ul><li>Add/Sub truncate silently — to capture carry extend operands or use uadd/sadd.</li><li>Many intrinsics handle width extension automatically (see Intrinsics section).</li></ul><hr><h2 id="special-operators-intrinsics-width-behavior" tabindex="-1">Special Operators &amp; Intrinsics (width behavior) <a class="header-anchor" href="#special-operators-intrinsics-width-behavior" aria-label="Permalink to “Special Operators &amp; Intrinsics (width behavior)”">​</a></h2><ul><li>uadd(a,b): unsigned add; result width = max(width(a),width(b)) + 1 (zero‑extend operands)</li><li>sadd(a,b): signed add; result width = max(width(a),width(b)) + 1 (sign‑extend operands)</li><li>umul(a,b): unsigned multiply; result width = 2 * max(width(a),width(b)) (zero‑extend)</li><li>smul(a,b): signed multiply; result width = 2 * max(width(a),width(b)) (sign‑extend)</li><li>gbit(source,index): returns 1 bit; index must be wide enough (&gt;= clog2(width(source))); out‑of‑range at runtime → returns 0</li><li>sbit(source,index,set): returns full source width with one bit updated</li><li>gslice/sslice: dynamic slice/overwrite with compile‑time constant slice width; index bounds behavior defined (out‑of‑range bits → 0 / ignored)</li></ul><p>Use intrinsics when you need automatic, safe extension or dynamic indexing semantics.</p><h3 id="lit-width-value-—-compile-time-integer-literal" tabindex="-1">lit(width, value) — compile-time integer literal <a class="header-anchor" href="#lit-width-value-—-compile-time-integer-literal" aria-label="Permalink to “lit(width, value) — compile-time integer literal”">​</a></h3><ul><li>Usage: <code>lit(width, value)</code></li><li>Materializes a compile-time integer into a sized, runtime-legal bit-vector</li><li>Both width and value must be compile-time nonnegative integer expressions (may reference <code>CONST</code>, <code>CONFIG</code>, <code>clog2()</code>, <code>widthof()</code>)</li><li>The value is zero-extended to the given width</li><li><code>lit()</code> is valid in ASYNCHRONOUS RHS, SYNCHRONOUS RHS, REGISTER reset values, and <code>@global</code> blocks</li><li><code>lit()</code> is <strong>not</strong> valid in width brackets, CONFIG blocks, CONST blocks, or OVERRIDE expressions</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Compare a register to a computed constant</span></span>
<span class="line"><span>IF (count == lit(ADDR, WIDTH - 1)) { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Use as a register reset value</span></span>
<span class="line"><span>REGISTER {</span></span>
<span class="line"><span>  limit [ADDR] = lit(ADDR, WIDTH - 1);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Errors:</span></span>
<span class="line"><span>lit(0, 5)            // ERROR: width must be &gt;= 1</span></span>
<span class="line"><span>lit(4, -1)           // ERROR: value &lt; 0</span></span>
<span class="line"><span>lit(4, 16)           // ERROR: overflow (16 &gt;= 2^4)</span></span>
<span class="line"><span>CONST { X = lit(4,3); } // ERROR: not a compile-time integer</span></span></code></pre></div><hr><h2 id="operator-precedence-highest-to-lowest" tabindex="-1">Operator precedence (highest to lowest) <a class="header-anchor" href="#operator-precedence-highest-to-lowest" aria-label="Permalink to “Operator precedence (highest to lowest)”">​</a></h2><ol><li>Parentheses <code>( )</code></li><li>Concatenation <code>{ }</code></li><li>Unary NOT <code>~</code> <code>!</code></li><li>Unary arithmetic <code>-</code> <code>+</code></li><li><code>*</code> <code>/</code> <code>%</code></li><li><code>&lt;&lt;</code> <code>&gt;&gt;</code> <code>&gt;&gt;&gt;</code></li><li>Binary <code>+</code> <code>-</code></li><li>Relational <code>&lt;</code> <code>&gt;</code> <code>&lt;=</code> <code>&gt;=</code></li><li>Equality <code>==</code> <code>!=</code></li><li>Bitwise <code>&amp;</code></li><li>Bitwise <code>^</code></li><li>Bitwise <code>|</code></li><li>Logical <code>&amp;&amp;</code></li><li>Logical <code>||</code></li><li>Ternary <code>? :</code></li></ol><hr><h2 id="compile‐time-helpers" tabindex="-1">Compile‑time helpers <a class="header-anchor" href="#compile‐time-helpers" aria-label="Permalink to “Compile‑time helpers”">​</a></h2><h3 id="clog2-value" tabindex="-1">clog2(value) <a class="header-anchor" href="#clog2-value" aria-label="Permalink to “clog2(value)”">​</a></h3><ul><li>Usage: <code>clog2(expr)</code></li><li>Evaluated at compile time; returns smallest bit count &gt;= value (ceil(log2(value)))</li><li>Argument must be a positive integer constant (CONST, CONFIG, or literal)</li><li>Typical use: address widths for memories, selector widths for MUX</li></ul><h3 id="widthof-identifier" tabindex="-1">widthof(identifier) <a class="header-anchor" href="#widthof-identifier" aria-label="Permalink to “widthof(identifier)”">​</a></h3><ul><li>Usage: <code>widthof(identifier)</code></li><li>Returns the declared static bit width of a BUS or local WIRE or REGISTER</li><li>Compile‑time only; name must be module‑local and resolvable</li><li>Not usable at run time inside ASYNCHRONOUS/SYNCHRONOUS expressions</li></ul><h3 id="const-vs-config-vs-global" tabindex="-1">CONST vs CONFIG vs @global <a class="header-anchor" href="#const-vs-config-vs-global" aria-label="Permalink to “CONST vs CONFIG vs @global”">​</a></h3><ul><li>CONST: module‑local integer constants, usable in widths and compile‑time contexts</li><li>CONFIG: project‑wide integer constants accessed as <code>CONFIG.NAME</code>, compile‑time only</li><li>@global: named sized literals (bit patterns) visible across modules and usable at run time in expressions</li></ul><p>Remember: CONST/CONFIG are compile‑time integers; @global entries are sized value literals usable in signal expressions.</p><h3 id="special-semantic-drivers" tabindex="-1">Special Semantic Drivers <a class="header-anchor" href="#special-semantic-drivers" aria-label="Permalink to “Special Semantic Drivers”">​</a></h3><p>To ensure electrical clarity and prevent manual bit-width matching errors for common constants, JZ-HDL defines two reserved semantic drivers: <code>GND</code> (Logic 0), <code>VCC</code> (Logic 1).</p><ul><li><strong>Polymorphic Expansion</strong>: Special drivers automatically expand to match the bit-width of the target identifier, satisfying the &quot;No Implicit Width Conversion&quot; rule by being width-agnostic by definition. The width of a special driver is determined solely by the width of the driven target, never by surrounding syntax.</li><li><strong>Atomic Assignment</strong>: Special drivers are valid only as standalone assignment tokens.</li><li><strong>Expression Proscription</strong>: To prevent ambiguous width inference in math, special drivers cannot be used as operands in arithmetic or logical expressions (e.g., <code>GND + 1</code> is illegal). <ul><li>may not appear in expressions</li><li>may not appear in concatenations</li><li>may not be sliced or indexed</li><li>may not appear in slice or index</li></ul></li><li><strong>Initialization</strong>: Special drivers are permitted as reset values in register declarations.</li></ul><p><strong>Target Constraints</strong>:</p><ul><li><code>GND</code> and <code>VCC</code> may drive any valid sink (wire, port, register, latch, etc.).</li></ul><p><strong>Driver Interaction:</strong></p><ul><li><code>GND</code> and <code>VCC</code> drivers participate fully in the Exclusive Assignment Rule.</li><li>Driving a signal with both a <code>GND</code> or <code>VCC</code> semantic driver and any other driver in the same execution path is illegal.</li></ul><hr><h2 id="common-errors-and-how-to-fix-them" tabindex="-1">Common errors and how to fix them <a class="header-anchor" href="#common-errors-and-how-to-fix-them" aria-label="Permalink to “Common errors and how to fix them”">​</a></h2><ul><li>Unsized literal (e.g., <code>&#39;hFF</code>): add width, e.g., <code>8&#39;hFF</code>.</li><li>Literal overflow: increase declared width or fix value to fit.</li><li>Operator width mismatch: make operand widths equal via explicit extension (<code>=z</code>, <code>=s</code>, concatenation, intrinsics) or adjust declarations.</li><li>Implicit truncation attempt: ensure LHS is wide enough or slice intentionally.</li><li>Using <code>x</code> or <code>z</code> in register resets / MEM init: replace with concrete 0/1 literal.</li><li>Unary <code>-</code> on multi‑bit: legal only for width‑1; for multi‑bit two&#39;s complement negate use subtraction: <code>zero - val</code> or use <code>sadd</code> patterns.</li><li>Division by zero (constant 0): fix divisor; if dynamic divisor may be zero, guard it with IF/ELSE.</li></ul><hr><h2 id="practical-examples" tabindex="-1">Practical examples <a class="header-anchor" href="#practical-examples" aria-label="Permalink to “Practical examples”">​</a></h2><p>Examples with expected behavior:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Valid: zero-extend 8-&gt;16 explicitly</span></span>
<span class="line"><span>wide_reg =z narrow_val;       // aliases (ASYNCHRONOUS) or use &lt;=z in SYNCHRONOUS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Capturing carry safely</span></span>
<span class="line"><span>{carry, sum} = uadd(a, b);    // result width = max(w(a),w(b)) + 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Full product</span></span>
<span class="line"><span>prod = umul(a, b);            // if a,b=8 -&gt; prod is 16 bits</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Illegal: unsized literal</span></span>
<span class="line"><span>data = &#39;hFF;                  // ERROR: unsized literal</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Illegal: overflow</span></span>
<span class="line"><span>4&#39;b10101;                     // ERROR: intrinsic width 5 &gt; declared 4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Binary literal with x: allowed but must be masked before observable sink</span></span>
<span class="line"><span>temp = 4&#39;b10x1;               // temp contains x; ensure downstream masking</span></span></code></pre></div><p>Memory/address helpers:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CONST { DEPTH = 256; }</span></span>
<span class="line"><span>ADDR_W = clog2(DEPTH);        // ADDR_W = 8</span></span></code></pre></div><p>widthof use:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>WIRE { bus [32]; }</span></span>
<span class="line"><span>CONST { W = widthof(bus); }   // valid compile-time query inside same module</span></span></code></pre></div><hr><h2 id="quick-checklist" tabindex="-1">Quick checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to “Quick checklist”">​</a></h2><ul><li>Always size literals: use the <code>width&#39;base_value</code> form.</li><li>Match operand widths for strict operators or use explicit extension (z/s).</li><li>Do not rely on implicit truncation — the compiler forbids it.</li><li>Avoid <code>x</code>/<code>z</code> reaching registers, MEM init, OUT/INOUT ports, top pins.</li><li>Use intrinsics (uadd, umul, ...) for safe automatic sizing when appropriate.</li><li>Use <code>clog2()</code> and <code>widthof()</code> for robust compile‑time sizing.</li><li>Ensure unary arithmetic is parenthesized (e.g., <code>(-a)</code>).</li></ul>`,85)])])}const m=i(n,[["render",l]]);export{u as __pageData,m as default};
